arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train the model and save it
var modelPath = TrainModel(Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv"));

// Register the thread-safe prediction engine pool
builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "ChurnPredictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (CustomerRequest request, PredictionEnginePool<CustomerInput, ChurnPrediction> pool) =>
{
    var input = new CustomerInput
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory,
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        willChurn = prediction.PredictedLabel,
        probability = prediction.Probability,
        score = prediction.Score,
    });
});

app.Run();

static string TrainModel(string dataPath)
{
    var mlContext = new MLContext(seed: 42);

    IDataView data = mlContext.Data.LoadFromTextFile<CustomerInput>(
        dataPath, hasHeader: true, separatorChar: ',');

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerInput.Region))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(CustomerInput.Age),
            nameof(CustomerInput.Income),
            nameof(CustomerInput.PurchaseHistory),
            "RegionEncoded"))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
            labelColumnName: nameof(CustomerInput.Churned),
            featureColumnName: "Features"));

    Console.WriteLine("Training churn prediction model...");
    var model = pipeline.Fit(split.TrainSet);

    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions,
        labelColumnName: nameof(CustomerInput.Churned));

    Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                      $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

    var modelPath = Path.Combine(Path.GetDirectoryName(dataPath)!, "churn_model.zip");
    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");

    return modelPath;
}

// Input schema matching the CSV
public class CustomerInput
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    [ColumnName("Label")]
    [BooleanLabel]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

// Maps "Yes"/"No" strings in the CSV to bool
[AttributeUsage(AttributeTargets.Property)]
public class BooleanLabelAttribute : Attribute { }

